#include <stdio.h>
#include <unistd.h>
#include <string.h>

/* == EXEMPLE =======================================
 * Rediriger stderr vers un pipe avec dup2
 * dup(fd) sauvegarde, dup2(src, dst) redirige.
 * Meme pattern que stdout mais avec STDERR_FILENO.
 * ================================================= */
void example_capture_stderr(void) {
    int p[2];
    pipe(p);
    int saved_stderr = dup(STDERR_FILENO);
    dup2(p[1], STDERR_FILENO);
    close(p[1]);
    fprintf(stderr, "error msg");
    fflush(stderr);
    dup2(saved_stderr, STDERR_FILENO);
    close(saved_stderr);
    char buf[64];
    ssize_t n = read(p[0], buf, sizeof(buf) - 1);
    buf[n] = '\0';
    close(p[0]);
    fprintf(stderr, "Caught: %s\n", buf);
}
